import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import logo from '../assets/Logo.png';

const Header = () => {
    const [categories, setCategories] = useState([]);
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => {

        axios.get('http://localhost:5000/api/categories')
            .then(res => setCategories(res.data))
            .catch(err => console.error("Erreur catégories:", err));
    }, []);

    return (
        <header className="bg-white border-bottom sticky-top">
            <div className="container py-3">
                <div className="row align-items-center">

                    <div className="col-12 col-md-4 text-center text-md-start">
                        <Link to="/">
                            <img src={logo} alt="Logo Région" style={{ height: '70px', width: 'auto' }} />
                        </Link>
                    </div>

                    <div className="col-12 col-md-8 mt-3 mt-md-0">
                        <div className="d-flex flex-column align-items-center align-items-md-end">

                            <div className="position-relative mb-2" style={{ width: '250px' }}>
                                <input
                                    className="form-control border-0 border-bottom rounded-0 shadow-none ps-0"
                                    type="text"
                                    placeholder="Rechercher"
                                    value={searchTerm}
                                    onChange={(e) => setSearchTerm(e.target.value)}
                                    style={{ borderBottom: '1px solid #004a99' }}
                                />
                                <span className="position-absolute end-0 top-50 translate-middle-y text-primary">
                                    🔍
                                </span>
                            </div>

                            <nav className="navbar navbar-expand-md navbar-light p-0">
                                <ul className="navbar-nav gap-2">
                                    {categories && categories.length > 0 ? (
                                        categories.map(cat => (
                                            <li className="nav-item" key={cat.id}>
                                                <Link className="nav-link text-dark fw-bold px-2" to={`/category/${cat.id}`}>
                                                    {cat.name}
                                                </Link>
                                            </li>
                                        ))
                                    ) : (
                                        <small className="text-muted">Chargement du menu...</small>
                                    )}
                                </ul>
                            </nav>
                        </div>
                    </div>
                </div>
            </div>
        </header>
    );
};

export default Header;
